import React, { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Tag, Select, message, DatePicker, Divider, Calendar, Modal, App, Breadcrumb, Flex 
} from "antd";
import { 
  SearchOutlined, DownloadOutlined,
  TableOutlined, BarChartOutlined,
  CalendarOutlined, LeftOutlined, RightOutlined,
  UnorderedListOutlined, InfoCircleOutlined, HomeOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import ExcelJS from "exceljs";
import dayjs from "dayjs";
import type { Dayjs } from 'dayjs';

const { useToken } = theme;
const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

// --- Mock Metadata (Should be bilingual if possible, but keep for now) ---
const mockOrgs = [
  { value: "all", label: "All Organizations" },
  { value: "team_a", label: "Labeling Team 1" },
  { value: "team_b", label: "Labeling Team 2" },
];

const mockRoles = [
  { value: "all", label: "All Roles" },
  { value: "worker", label: "Labeler" },
  { value: "inspector", label: "Inspector" },
];

const generateDateRange = (start: string, days: number) => {
  const dates = [];
  let curr = dayjs(start);
  for (let i = 0; i < days; i++) {
    dates.push(curr.format('YYYY-MM-DD'));
    curr = curr.add(1, 'day');
  }
  return dates;
};
const fullDates = generateDateRange('2023-07-01', 31);

const initialWorkerData = [
  { key: "1", userId: "user001", name: "J. Kim", org: "Team 1", role: "Labeler", daily: fullDates.reduce((acc: any, d) => ({...acc, [d]: Math.floor(Math.random() * 50)}), {}), color: "#1890ff" },
  { key: "2", userId: "user002", name: "S. Lee", org: "Team 1", role: "Labeler", daily: fullDates.reduce((acc: any, d) => ({...acc, [d]: Math.floor(Math.random() * 40)}), {}), color: "#52c41a" },
  { key: "3", userId: "user003", name: "D. Park", org: "Team 2", role: "Inspector", daily: fullDates.reduce((acc: any, d) => ({...acc, [d]: Math.floor(Math.random() * 30)}), {}), color: "#722ed1" },
];

export default function StatWorkerPage() {
  const { token } = useToken();
  const { t } = useTranslation(["stats", "common", "user", "labeling"]);
  const { message } = App.useApp();

  const [viewMode, setViewMode] = useState<"grid" | "chart" | "calendar">("grid");
  const [selectedOrg, setSelectedOrg] = useState<string>("all");
  const [selectedRole, setSelectedRole] = useState<string>("all");
  const [dateRange, setDateRange] = useState<any>([dayjs('2023-07-01'), dayjs('2023-07-31')]);
  const [calendarValue, setCalendarValue] = useState<Dayjs>(dayjs('2023-07-01'));
  const [displayData, setDisplayData] = useState(initialWorkerData);
  const [loading, setLoading] = useState(false);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDateStr, setSelectedDateStr] = useState("");

  const handleSearch = () => {
    setLoading(true);
    setTimeout(() => {
      setDisplayData(initialWorkerData);
      setLoading(false);
      message.success(t("search", { ns: "common" }));
    }, 400);
  };

  const handleDateClick = (value: Dayjs) => {
    setSelectedDateStr(value.format('YYYY-MM-DD'));
    setIsModalOpen(true);
  };

  const dateCellRender = (value: Dayjs) => {
    const dateStr = value.format('YYYY-MM-DD');
    const records = displayData.filter(w => (w.daily as any)[dateStr] > 0);
    return (
      <div style={{ padding: 4 }}>
        {records[0] && (
          <div style={{ fontSize: 10, background: token.colorPrimary, color: "white", padding: "2px 4px", borderRadius: 4, marginBottom: 2 }}>
            {records[0].name}: {(records[0].daily as any)[dateStr]}
          </div>
        )}
        {records.length > 1 && <div style={{ fontSize: 9, color: token.colorTextDescription }}>+ {records.length - 1} others</div>}
      </div>
    );
  };

  const tableColumns = useMemo(() => [
    { title: t("userId", { ns: "user" }), dataIndex: "userId", fixed: "left" as const, width: 120 },
    { title: t("userName", { ns: "user" }), dataIndex: "name", fixed: "left" as const, width: 100 },
    { title: t("org", { ns: "user" }), dataIndex: "org", width: 120 },
    { title: t("role", { ns: "user" }), dataIndex: "role", width: 100, render: (v: string) => <Tag color={v.includes("Inspector") ? "purple" : "blue"}>{v}</Tag> },
    ...fullDates.map(d => ({ title: d, dataIndex: ["daily", d], key: d, width: 80, align: "right" as const })),
  ], [t]);

  const handleExport = async () => {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet("Performance");
    worksheet.columns = [
      { header: t("userId", { ns: "user" }), key: "uid", width: 15 },
      { header: t("userName", { ns: "user" }), key: "unm", width: 15 },
      { header: "Total", key: "total", width: 15 },
    ];
    displayData.forEach(d => worksheet.addRow({ uid: d.userId, unm: d.name, total: Object.values(d.daily).reduce((a: any, b: any) => a + b, 0) }));
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const link = document.createElement("a");
    link.href = window.URL.createObjectURL(blob);
    link.download = `PerformanceReport_${dayjs().format("YYYYMMDD")}.xlsx`;
    link.click();
    message.success(t("confirm", { ns: "common" }));
  };

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("tabs.personal")}</Title>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") },
              { title: t("tabs.personal") }
            ]} 
          />
          <Space wrap>
            <RangePicker size="small" value={dateRange} onChange={setDateRange} style={{ width: 230 }} />
            <Select size="small" value={selectedOrg} onChange={setSelectedOrg} style={{ width: 140 }} options={mockOrgs} />
            <Select size="small" value={selectedRole} onChange={setSelectedRole} style={{ width: 110 }} options={mockRoles} />
            <Divider type="vertical" />
            <Space.Compact size="small">
              <Button icon={<TableOutlined />} type={viewMode === "grid" ? "primary" : "default"} onClick={() => setViewMode("grid")}></Button>
              <Button icon={<BarChartOutlined />} type={viewMode === "chart" ? "primary" : "default"} onClick={() => setViewMode("chart")}></Button>
              <Button icon={<CalendarOutlined />} type={viewMode === "calendar" ? "primary" : "default"} onClick={() => setViewMode("calendar")}></Button>
            </Space.Compact>
            <Button type="primary" size="small" icon={<SearchOutlined />} onClick={handleSearch} loading={loading}>{t("search", { ns: "common" })}</Button>
            <Button size="small" icon={<DownloadOutlined />} onClick={handleExport}>{t("confirm", { ns: "common" })}</Button>
          </Space>
        </Flex>
      </div>

      <Card variant="borderless" styles={{ body: { padding: 0 } }} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, overflow: "hidden" }}>
        {viewMode === "grid" && (
          <Table dataSource={displayData} columns={tableColumns} size="small" pagination={false} loading={loading} scroll={{ x: "max-content", y: 500 }} bordered />
        )}
        {viewMode === "chart" && (
          <div style={{ padding: 24 }}>
            <ReactECharts 
              option={{
                xAxis: { type: 'category', data: fullDates.map(d => dayjs(d).format('MM-DD')) },
                yAxis: { type: 'value' },
                series: displayData.map(w => ({ name: w.name, type: 'line', data: Object.values(w.daily) }))
              }} 
              style={{ height: 500 }} 
            />
          </div>
        )}
        {viewMode === "calendar" && (
          <Calendar 
            fullscreen={true} value={calendarValue} onSelect={handleDateClick} dateCellRender={dateCellRender}
            headerRender={({ value, onChange }) => (
              <div style={{ padding: 16, display: "flex", justifyContent: "center", alignItems: "center", gap: 32 }}>
                <Button type="text" icon={<LeftOutlined />} onClick={() => onChange(value.clone().subtract(1, 'month'))} />
                <Title level={4} style={{ margin: 0 }}>{value.format('MMMM YYYY')}</Title>
                <Button type="text" icon={<RightOutlined />} onClick={() => onChange(value.clone().add(1, 'month'))} />
              </div>
            )}
          />
        )}
      </Card>

      <Modal
        title={<Space><UnorderedListOutlined /> <Text strong>{t("personal.detailTitle")} ({selectedDateStr})</Text></Space>}
        open={isModalOpen} onCancel={() => setIsModalOpen(false)} footer={null} width={700} centered
      >
        <Table 
          dataSource={displayData.filter(w => (w.daily as any)[selectedDateStr] > 0).map(w => ({ ...w, count: (w.daily as any)[selectedDateStr] }))}
          pagination={false} size="small"
          columns={[
            { title: t("userName", { ns: "user" }), dataIndex: "name" },
            { title: t("org", { ns: "user" }), dataIndex: "org" },
            { title: t("role", { ns: "user" }), dataIndex: "role" },
            { title: t("processed", { ns: "stats" }), dataIndex: "count", align: "right", render: (v) => <Text strong>{v} {t("unitCases", { ns: "common" })}</Text> },
          ]}
        />
      </Modal>

      <style>{`
        .ant-table-thead > tr > th { background-color: ${token.colorFillTertiary} !important; font-size: 11px !important; }
        .ant-table-cell { font-size: 11px !important; }
        .ant-calendar-cell { min-height: 120px !important; border: 1px solid ${token.colorBorderSecondary} !important; }
      `}</style>
    </div>
  );
}
